            f.lineinfo[basepc as usize] != ABS_LINE_INFO,
            "get_func_line: hit ABSLINEINFO in incremental walk"
        );
        // C: baseline += f->lineinfo[basepc]
        baseline += f.lineinfo[basepc as usize] as i32;
    }
    baseline
}

